// ── FILE HANDLER ──────────────────────────────────────────────────────────────
function handleFile(file){
  if(!file)return;
  if(!file.name.toLowerCase().match(/\.fit$/i)){
    showDiag('err','Unsupported file','<p>Expected a <strong>.fit</strong> file. Got: <strong>'+file.name.split('.').pop()+'</strong></p>');return;
  }
  $('diag').style.display='none';$('results').style.display='none';
  setStatus('Reading FIT file...');
  const cp=parseInt($('cp').value)||263;
  const hrRest=parseInt($('hrrest').value)||48;
  const hrmaxResult=getHrmax();
  const hrMax=hrmaxResult.val||178;
  const hrmaxEstimated=hrmaxResult.estimated;
  const reader=new FileReader();
  reader.onload=async function(e){
    try{
      setStatus('Parsing FIT binary...');
      const records=parseFIT(e.target.result);
      if(!records.length){hideStatus();showDiag('err','No data','<p>No HR/power records found in file.</p>');return;}
      setStatus('Classifying workout type...');
      const wk=classify(records,cp);
      if(wk.type==='no_data'){hideStatus();showDiag('err','No usable data','<p>No power or HR data found.</p>');return;}
      if(wk.type!=='protocol'&&wk.type!=='step'){
        hideStatus();
        showDiag('warn','Wrong workout type','<p>'+wk.desc+'</p>'+(wk.rec?'<p>'+wk.rec+'</p>':'')+statsHTML(wk));return;
      }
      setStatus('Detecting stages...');
      const stages=detectStages(records,cp);
      if(stages.length<3){
        hideStatus();showDiag('warn','Too few stages','<p>Only <strong>'+stages.length+' stage(s)</strong> isolated.</p>'+statsHTML(wk));return;
      }
      setStatus('Analyzing thresholds...');
      const A=analyze(stages,cp,hrRest,hrMax,hrmaxEstimated);
      if(!A){hideStatus();showDiag('err','Analysis failed','<p>Insufficient stage data for threshold detection.</p>');return;}
      _analysis=A;
      hideStatus();
      showDiag('ok',(wk.type==='protocol'?'Recovery-valley protocol':'Step test')+' confirmed — '+stages.length+' stages','<p>'+wk.desc+'</p>'+statsHTML(wk));
      $('results').style.display='block';
      renderSummary(A);
      renderFlags(A);
      renderZones(A);
      renderConf(A);
      renderCharts(A);
      renderTable(A);
      await getAI(A);
    }catch(err){
      hideStatus();showDiag('err','Parse error','<p><strong>'+err.message+'</strong></p>');
    }
  };
  reader.readAsArrayBuffer(file);
}

function setStatus(msg){const s=$('status-bar');s.style.display='flex';$('status-text').textContent=msg;}
function hideStatus(){$('status-bar').style.display='none';}
function showDiag(level,title,html){
  const d=$('diag');d.style.display='block';
  const ic=$('diag-icon');ic.className='diag-icon di-'+level;ic.textContent=level==='ok'?'✓':level==='warn'?'!':'✕';
  $('diag-title').className='dt-'+level;$('diag-title').textContent=title;
  $('diag-body').innerHTML=html;
}
function statsHTML(w){return`<div class="diag-stats"><div class="ds"><div class="ds-l">Duration</div><div class="ds-v">${Math.round(w.durMin)} min</div></div><div class="ds"><div class="ds-l">Power range</div><div class="ds-v">${Math.round(w.minP)}–${Math.round(w.maxP)}W</div></div><div class="ds"><div class="ds-l">Stages</div><div class="ds-v">${w.ups}</div></div><div class="ds"><div class="ds-l">Recoveries</div><div class="ds-v">${w.downs}</div></div></div>`;}

const dz=$('drop-zone'),fi=$('fit-file');
fi.addEventListener('change',e=>{if(e.target.files[0])handleFile(e.target.files[0]);});
dz.addEventListener('dragover',e=>{e.preventDefault();dz.classList.add('drag');});
dz.addEventListener('dragleave',()=>dz.classList.remove('drag'));
dz.addEventListener('drop',e=>{e.preventDefault();dz.classList.remove('drag');if(e.dataTransfer.files[0])handleFile(e.dataTransfer.files[0]);});

